import{_ as t,o as a,c as o,ae as n}from"./chunks/framework.BNdaYNh3.js";const i="/linux-notes/assets/20250308123342.oLXzruXc.png",m=JSON.parse('{"title":"System Installation","description":"","frontmatter":{},"headers":[],"relativePath":"notes/system-installation.md","filePath":"notes/system-installation.md"}'),l={name:"notes/system-installation.md"};function r(s,e,h,d,c,u){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="system-installation" tabindex="-1">System Installation <a class="header-anchor" href="#system-installation" aria-label="Permalink to &quot;System Installation&quot;">​</a></h1><h2 id="version-history" tabindex="-1">Version History <a class="header-anchor" href="#version-history" aria-label="Permalink to &quot;Version History&quot;">​</a></h2><ul><li>Deepin 23.1: <a href="https://github.com/duanluan/linux-notes/tree/deepin23" target="_blank" rel="noreferrer">GitHub - duanluan/deepin-notes at deepin23</a></li><li>Xubuntu 24.04.2: <a href="https://github.com/duanluan/linux-notes/tree/xubuntu24" target="_blank" rel="noreferrer">GitHub - duanluan/linux-notes at xubuntu24</a></li><li>Manjaro: current version</li></ul><h2 id="create-the-installation-usb" tabindex="-1">Create the Installation USB <a class="header-anchor" href="#create-the-installation-usb" aria-label="Permalink to &quot;Create the Installation USB&quot;">​</a></h2><p>Install <a href="https://www.ventoy.net/cn/index.html" target="_blank" rel="noreferrer">Ventoy</a> on the USB drive.</p><p><img src="'+i+'" alt="Ventoy2Disk"></p><p>On the <a href="https://manjaro.org/" target="_blank" rel="noreferrer">Manjaro Homepage</a>, click <code>Download</code>, choose the <code>KDE Plasma</code> edition, download the ISO, and place it on the USB drive.</p><h2 id="install-the-system" tabindex="-1">Install the System <a class="header-anchor" href="#install-the-system" aria-label="Permalink to &quot;Install the System&quot;">​</a></h2><p>For more details, see: <a href="https://wiki.manjaro.org/index.php/UEFI_-_Install_Guide/zh-cn" target="_blank" rel="noreferrer">UEFI - Installation Guide - Manjaro</a></p><p>Press <code>F2</code> or <code>Del</code> during boot to enter the BIOS, then choose the USB drive under <code>Save &amp; Exit</code> -&gt; <code>Boot Override</code>.</p><p>In Ventoy, choose the Manjaro image and select <code>Boot in normal mode</code>. If you run into boot issues, try <code>Boot in grub2 mode</code>.</p><p>Set tz (time zone) to <code>Asia/Shanghai</code> and lang (language) to <code>zh_CN</code>. After that, pacman will switch to the corresponding mirrors automatically.</p><p>Choose <code>Boot with open source drivers</code>. After the desktop loads, click <code>Launch installer</code> in the <code>Manjaro Hello</code> window.</p><p>Installer settings:</p><ul><li>Location <ul><li>Set the time zone to Asia/Shanghai.</li><li>Set the system language to Simplified Chinese (China).</li><li>Set the numbers and dates locale to Simplified Chinese (China).</li></ul></li><li>Keyboard <ul><li>Set the keyboard model to Generic 105-key PC.</li><li>Set the keyboard layout to Chinese/Default.</li></ul></li><li>Partitions <ul><li>Erase disk</li><li>Choose swap without hibernation, or swap with hibernation + ext4. For laptops, the hibernation option is recommended.</li></ul></li><li>Office Suite <ul><li>No Office Suite</li></ul></li></ul><p>After installation finishes, remove the USB drive before rebooting.</p><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li><a href="https://blog.zhjh.top/?p=pe" target="_blank" rel="noreferrer">Clean ad-free PE boot tools and multi-system collection</a></li><li><a href="https://ventoy.net/cn/doc_grub2boot.html" target="_blank" rel="noreferrer">grub2boot . Ventoy</a></li></ul>',18)])])}const f=t(l,[["render",r]]);export{m as __pageData,f as default};
